"""
offsets.py - ART structure offset tables extracted directly from
OpenCoreAnalysisKit source (android/art/runtime/runtime.cpp,
mirror/class.cpp, thread.cpp, etc.).

Layout: OFFSETS[struct_name][sdk] = {field: offset, ...}
sdk key is the *minimum* SDK for which this layout applies.
Call get_offsets(struct_name, sdk, bits) to get the right dict.
"""

# ── helpers ──────────────────────────────────────────────────────────

def get_offsets(name: str, sdk: int, bits: int = 64) -> dict:
    """Return the offset dict for struct `name` at given sdk/bits."""
    table = OFFSETS.get(name, {})
    # pick the entry with the largest min_sdk <= sdk
    chosen = None
    for min_sdk, by_bits in sorted(table.items()):
        if sdk >= min_sdk:
            chosen = by_bits
    if chosen is None:
        return {}
    return chosen.get(bits, chosen.get(64, {}))


def get_size(name: str, sdk: int, bits: int = 64) -> int:
    return get_offsets(name, sdk, bits).get('THIS', 0)


